package com.samlong.model;
import javax.persistence.*;import javax.validation.constraints.*;
@Entity @Table(name="slides") public class Slide {
 @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @NotBlank(message="轮播标题不能为空") @Size(max=255) private String title; @Size(max=255) private String subtitle; @Size(max=255) private String eyebrow; @NotBlank(message="轮播图片不能为空") @Size(max=500) @Pattern(regexp="^https?://.+|^/(uploads|images)/.+",message="轮播图片地址格式不正确") private String imageUrl; @Size(max=500) @Pattern(regexp="^$|^#.+|^https?://.+|^/.+",message="跳转链接格式不正确") private String linkUrl; @NotBlank(message="轮播状态不能为空") @Pattern(regexp="ACTIVE|DRAFT",message="轮播状态只能是发布或草稿") private String status="ACTIVE"; @NotNull(message="排序不能为空") @Min(value=0,message="排序不能小于0") private Integer sortOrder=0;
 public Long getId(){return id;}public void setId(Long v){id=v;}public String getTitle(){return title;}public void setTitle(String v){title=v;}public String getSubtitle(){return subtitle;}public void setSubtitle(String v){subtitle=v;}public String getEyebrow(){return eyebrow;}public void setEyebrow(String v){eyebrow=v;}public String getImageUrl(){return imageUrl;}public void setImageUrl(String v){imageUrl=v;}public String getLinkUrl(){return linkUrl;}public void setLinkUrl(String v){linkUrl=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public Integer getSortOrder(){return sortOrder;}public void setSortOrder(Integer v){sortOrder=v;}
}
